def get_coordinates(address: str | None) -> tuple[float, float]:
    """
    주소 문자열에서 위경도를 추출한다.

    Returns:
        (latitude, longitude) 튜플
    """
    if not address:
        return DEFAULT_COORDS

    # 1) 시/군/구 단위 매칭
    for region, coords in _REGION_COORDS.items():
        if region in address:
            logger.info(f"[Geocoding] '{address}' -> {region} ({coords[0]}, {coords[1]})")
            return coords

    # 2) 도 단위 매칭
    for province, coords in _PROVINCE_COORDS.items():
        if province in address:
            logger.info(f"[Geocoding] '{address}' -> {province} ({coords[0]}, {coords[1]})")
            return coords

    logger.info(f"[Geocoding] '{address}' -> 매칭 실패, 기본 좌표 사용")
    return DEFAULT_COORDS
